import os
import csv
import json
import numpy as np
import pandas as pd
from PIL import Image

import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import LabelEncoder

from flask import Flask, request, jsonify, render_template_string
from werkzeug.utils import secure_filename

# --- Configuration ---
UPLOAD_FOLDER = 'uploaded_data'
LABELS_CSV = os.path.join(UPLOAD_FOLDER, 'labels.csv')
MODEL_PATH = 'trained_model'
IMAGE_SIZE = (128, 128)
BATCH_SIZE = 32
EPOCHS = 5 # Reduced for quicker demonstration; increase for better accuracy
VAL_SPLIT = 0.2

# --- Setup Directories ---
os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_PATH, exist_ok=True)

# Initialize labels.csv if it doesn't exist
if not os.path.exists(LABELS_CSV):
    with open(LABELS_CSV, 'w', newline='') as f:
        writer = csv.writer(f)
        writer.writerow(['image_path', 'label'])
    print(f"Created {LABELS_CSV}")

# --- Flask App ---
app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# A simple HTML form for interaction
