@app.route('/')
def index():
    try:
        df = pd.read_csv(LABELS_CSV)
        num_examples = len(df)
    except pd.errors.EmptyDataError:
        num_examples = 0

    model_status = "Not trained yet"
    if os.path.exists(os.path.join(MODEL_PATH, 'saved_model.pb')):
        model_status = "Trained (a model exists)"

    return render_template_string(HTML_FORM, num_examples=num_examples, model_status=model_status)

@app.route('/contribute_example', methods=['POST'])
def contribute_example():
    if 'image' not in request.files:
        return jsonify({"error": "No image file part"}), 400
    if 'label' not in request.form:
        return jsonify({"error": "No label provided"}), 400

    image_file = request.files['image']
    label = request.form['label'].strip()

    if image_file.filename == '':
        return jsonify({"error": "No selected image file"}), 400
    if not label:
        return jsonify({"error": "Label cannot be empty"}), 400

    try:
        filename = secure_filename(image_file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)

        # To avoid overwriting, generate a unique filename if it already exists
        counter = 1
        original_filename_base, original_filename_ext = os.path.splitext(filename)
        while os.path.exists(filepath):
            filename = f"{original_filename_base}_{counter}{original_filename_ext}"
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            counter += 1

        image_file.save(filepath)

        with open(LABELS_CSV, 'a', newline='') as f:
            writer = csv.writer(f)
            writer.writerow([filename, label]) # Store filename (relative path to UPLOAD_FOLDER)

        return jsonify({"message": f"Image '{filename}' with label '{label}' uploaded successfully."})

    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/upload_csv', methods=['POST'])
def upload_csv():
    """
    Uploads a CSV file containing 'image_path', 'label' pairs.
    Assumes images listed in the CSV are already present in UPLOAD_FOLDER
    or will be uploaded separately. This endpoint updates the central LABELS_CSV.
    """
    if 'labels_csv' not in request.files:
        return jsonify({"error": "No CSV file part"}), 400

    csv_file = request.files['labels_csv']

    if csv_file.filename == '':
        return jsonify({"error": "No selected CSV file"}), 400

    if not csv_file.filename.endswith('.csv'):
        return jsonify({"error": "File must be a CSV"}), 400

    try:
        # Read the uploaded CSV
        df_new_labels = pd.read_csv(csv_file)
        if not all(col in df_new_labels.columns for col in ['image_path', 'label']):
            return jsonify({"error": "CSV must contain 'image_path' and 'label' columns"}), 400

        # Read existing labels
        try:
            df_existing = pd.read_csv(LABELS_CSV)
        except pd.errors.EmptyDataError:
            df_existing = pd.DataFrame(columns=['image_path', 'label'])

        # Append new labels and remove duplicates (prioritizing new labels if 'image_path' clashes)
        df_combined = pd.concat([df_existing, df_new_labels]).drop_duplicates(subset=['image_path'], keep='last')

        # Save the combined DataFrame back to LABELS_CSV
        df_combined.to_csv(LABELS_CSV, index=False)

        return jsonify({"message": f"CSV with {len(df_new_labels)} labels uploaded and integrated successfully."})

    except Exception as e:
        return jsonify({"error": str(e)}), 500


# --- TensorFlow Model & Training ---

def load_and_preprocess_image(image_path_tensor, label_tensor):
    # Ensure image_path is absolute or relative to current working directory
    # For this setup, it's relative to UPLOAD_FOLDER, so make it absolute for tf.io
    full_image_path = tf.strings.join([os.path.abspath(UPLOAD_FOLDER), '/', image_path_tensor])
    img = tf.io.read_file(full_image_path)
    img = tf.image.decode_image(img, channels=3) # Decode to 3 color channels
    img = tf.image.convert_image_dtype(img, tf.float32) # Normalize to [0,1]
    img = tf.image.resize(img, IMAGE_SIZE) # Resize to target size
    return img, label_tensor

def build_model(num_classes):
    model = keras.Sequential([
        layers.Conv2D(32, (3, 3), activation='relu', input_shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 3)),
        layers.MaxPooling2D((2, 2)),
        layers.Conv2D(64, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Conv2D(128, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Flatten(),
        layers.Dense(128, activation='relu'),
        layers.Dense(num_classes, activation='softmax')
    ])
    return model

@app.route('/train', methods=['POST'])
def train_model_endpoint():
    try:
        df = pd.read_csv(LABELS_CSV)
    except pd.errors.EmptyDataError:
        return jsonify({"error": "No training data available. Please upload images and labels first."}), 400

    # Ensure all image paths in LABELS_CSV actually exist in the UPLOAD_FOLDER
    df['full_path'] = df['image_path'].apply(lambda x: os.path.join(UPLOAD_FOLDER, x))
    df = df[df['full_path'].apply(os.path.exists)]

    if len(df) < 2:
         return jsonify({"error": f"Not enough training data after filtering for existing images ({len(df)} examples). Need at least 2 examples."}), 400

    image_paths = df['image_path'].tolist()
    labels = df['label'].tolist()

    # Encode labels to integers
    label_encoder = LabelEncoder()
    integer_labels = label_encoder.fit_transform(labels)
    num_classes = len(label_encoder.classes_)

    # Save label encoder classes for future inference (to map integer predictions back to original labels)
    np.save(os.path.join(MODEL_PATH, 'label_classes.npy'), label_encoder.classes_)

    # Create tf.data.Dataset
    path_ds = tf.data.Dataset.from_tensor_slices(image_paths)
    label_ds = tf.data.Dataset.from_tensor_slices(tf.cast(integer_labels, tf.int64)) # Use tf.int64 for sparse_categorical_crossentropy

    image_label_ds = tf.data.Dataset.zip((path_ds, label_ds))
    dataset = image_label_ds.map(load_and_preprocess_image, num_parallel_calls=tf.data.AUTOTUNE)
    
    # Shuffle and batch the entire dataset
    dataset = dataset.shuffle(buffer_size=len(df)).batch(BATCH_SIZE).prefetch(buffer_size=tf.data.AUTOTUNE)

    # Calculate sizes for train/validation split (based on number of batches)
    total_batches = tf.data.experimental.cardinality(dataset).numpy()
    if total_batches == tf.data.experimental.INFINITE_CARDINALITY:
        return jsonify({"error": "Dataset cardinality is infinite, cannot split. This should not happen."}), 500

    train_batches = int((1 - VAL_SPLIT) * total_batches)
    val_batches = total_batches - train_batches

    if train_batches == 0:
        return jsonify({"error": "Training dataset is empty after split. Please add more data or adjust VAL_SPLIT."}), 400
    
    # Split the dataset into training and validation
    train_ds = dataset.take(train_batches)
    val_ds = dataset.skip(train_batches)

    # If validation set is empty, train without it (e.g., if only one batch total)
    if val_batches == 0:
        val_ds = None
        print("Warning: Validation dataset is empty. Training without validation.")

    model = build_model(num_classes)
    model.compile(
        optimizer='adam',
        loss=tf.keras.losses.SparseCategoricalCrossentropy(),
        metrics=['accuracy']
    )

    print(f"Starting training with {len(df)} examples across {num_classes} classes...")
    if val_ds:
        history = model.fit(train_ds, epochs=EPOCHS, validation_data=val_ds)
    else:
        history = model.fit(train_ds, epochs=EPOCHS)

    # Save the entire model in TensorFlow SavedModel format
    model.save(MODEL_PATH)

    return jsonify({
        "message": "Model training completed successfully.",
        "final_accuracy": float(history.history['accuracy'][-1]),
        "final_val_accuracy": float(history.history['val_accuracy'][-1]) if val_ds else 'N/A',
        "num_examples_trained": len(df),
        "num_classes": num_classes,
        "classes": label_encoder.classes_.tolist()
    })

if __name__ == '__main__':
    # Run the Flask app
    # For development, debug=True. In production, use a WSGI server like Gunicorn or uWSGI.
    app.run(debug=True, host='0.0.0.0', port=5000)